/* Minimal local marked-compatible parser for markdown rendering in static environments. */
(function (global) {
  function escapeHtml(value) {
    return String(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;");
  }

  function renderLine(line) {
    if (/^###\s+/.test(line)) return "<h3>" + escapeHtml(line.replace(/^###\s+/, "")) + "</h3>";
    if (/^##\s+/.test(line)) return "<h2>" + escapeHtml(line.replace(/^##\s+/, "")) + "</h2>";
    if (/^#\s+/.test(line)) return "<h1>" + escapeHtml(line.replace(/^#\s+/, "")) + "</h1>";
    if (/^\-\s+/.test(line)) return "<li>" + escapeHtml(line.replace(/^\-\s+/, "")) + "</li>";
    if (!line.trim()) return "";
    return "<p>" + escapeHtml(line) + "</p>";
  }

  function parse(markdown) {
    var lines = String(markdown || "").split(/\r?\n/);
    var out = [];
    var inList = false;

    for (var i = 0; i < lines.length; i++) {
      var html = renderLine(lines[i]);
      if (!html) {
        if (inList) {
          out.push("</ul>");
          inList = false;
        }
        continue;
      }
      if (html.indexOf("<li>") === 0) {
        if (!inList) {
          out.push("<ul>");
          inList = true;
        }
        out.push(html);
      } else {
        if (inList) {
          out.push("</ul>");
          inList = false;
        }
        out.push(html);
      }
    }

    if (inList) out.push("</ul>");
    return out.join("\n");
  }

  global.marked = { parse: parse };
})(window);
